INSERT INTO RCA.tb_rca_ticket_handling_status_current(
  TICKET_ID
  , STATUS
  , HANDLING_USER
  , HANDLING_DEPT
  , HANDLING_TIME
  , HANDLING_AGENCY
  , HANDLING_CONTENT
  , HANDLING_FIN_CONTENT
  , RCA_ACCURACY
  , REASON_LEVEL1
  , REASON_LEVEL2
  , REASON_LEVEL3
  , CHARGE_LEVEL1
  , CHARGE_LEVEL2
  , FIN_LEVEL1
  , HANDLING_FIN_USER
  , HANDLING_FIN_DEPT
  , HANDLING_FIN_AGENCY
  , INSERT_TIME
)
VALUES (
        #{ticketId}
       , #{status}
       , #{handlingUser}
       , #{handlingDept}
       , (SELECT NOW())
       , #{handlingAgency}
       , #{handlingContent}
       , #{handlingFinContent}
       , #{rcaAccuracy}
       , #{reasonLevel1}
       , #{reasonLevel2}
       , #{reasonLevel3}
       , #{chargeLevel1}
       , #{chargeLevel2}
       , #{finLevel1}
       , #{handlingFinUser}
       , #{handlingFinDept}
       , #{handlingFinAgency}
       , (SELECT TICKET_GENERATION_TIME FROM RCA.TB_RCA_TICKET_CURRENT WHERE TICKET_ID = #{ticketId})
)

