UPDATE RCA.tb_rca_ticket_handling_status_current
SET STATUS    				= #{status}
        , HANDLING_USER			= #{handlingUser}
        , HANDLING_DEPT			= #{handlingDept}
        , HANDLING_TIME			= (SELECT NOW())
        , HANDLING_AGENCY		= #{handlingAgency}
        , HANDLING_CONTENT		= #{handlingContent}
        , HANDLING_FIN_CONTENT	= #{handlingFinContent}
        , RCA_ACCURACY			= #{rcaAccuracy}
        , REASON_LEVEL1			= #{reasonLevel1}
        , REASON_LEVEL2			= #{reasonLevel2}
        , REASON_LEVEL3			= #{reasonLevel3}
        , CHARGE_LEVEL1			= #{chargeLevel1}
        , CHARGE_LEVEL2			= #{chargeLevel2}
        , FIN_LEVEL1				= #{finLevel1}
        , HANDLING_FIN_USER		= #{handlingFinUser}
        , HANDLING_FIN_DEPT		= #{handlingFinDept}
        , HANDLING_FIN_AGENCY	= #{handlingFinAgency}
WHERE TICKET_ID    			= #{ticketId}

