UPDATE RCA.tb_rca_ticket_current
SET PARENT_TICKET_ID = #{parentTicketId}
WHERE TICKET_ID = #{ticketId}
   OR PARENT_TICKET_ID = #{ticketId}

UPDATE RCA.tb_rca_ticket_current
SET TICKET_UPDATE_TIME = TO_TIMESTAMP(#{ticketUpdateTime}, 'YYYY-MM-DD HH24:MI:SS')
WHERE TICKET_ID = #{ticketId}

UPDATE RCA.TB_RCA_TICKET_CNT
   SET CHILD_COUNT = (SELECT COUNT(TICKET_ID) FROM RCA.TB_RCA_TICKET_CURRENT WHERE PARENT_TICKET_ID = #{parentTicketId})
 WHERE TICKET_ID = #{parentTicketId}

