UPDATE nia.tb_sop
SET receive_time = now(), status = #{status}
WHERE sop_id = #{sopId}

UPDATE rca.tb_rca_ticket_current
SET status = #{status}
WHERE ticket_id = #{ticketId}

mapper.select:
   SELECT A.PROFILE_TITLE as profileTitle, A.AUTO_RECOVERY as autoRecovery, B.PORT_ID as portId
     FROM RESOURCE.TB_FAULT_PROCESS_PROFILE A
     LEFT OUTER JOIN RESOURCE.TB_FAULT_PROCESS_IF B
       ON A.PROFILE_NUM = B.PROFILE_NUM
   WHERE A.NETWORK_TYPE = #{networkType}

     AND A.PROCESS_TYPE = #{processType}


     AND (B.NODE_ID = #{nodeId})


AND (A.AUTO_PROCESS_CHECK = TRUE OR (A.AUTO_PROCESS_END_DATETIME > #{faultTime}::timestamp AND A.AUTO_PROCESS_START_DATETIME < #{faultTime}::timestamp)) 


     AND B.PORT_ID = #{portId}

   limit 1

