UPDATE RCA.TB_ANOMALOUS_TRAFFIC
SET TICKET_ID = #{ticketId}
WHERE STRIFID = #{strifid} AND INTTIMESTAMP = #{inttimestamp}::int

UPDATE RCA.TB_NOXIOUS_TRAFFIC
SET TICKET_ID = #{ticketId}
WHERE STRRESIP = #{strresip} AND STRS_IP = #{strsIp} AND STRS_PORT = #{strsPort} AND STRD_IP = #{strdIp} AND STRD_PORT = #{strdPort} AND DATEREGDATE = #{dateregdate}::timestamp

mapper.select:
SELECT
    STRRESIP, STRRESNAME, STRS_IP, STRS_PORT, STRD_IP,
    STRD_PORT, STRS_MAC, STRD_MAC, STRPROTOCOL, STRIPV4TOS,
    STRCHANNEL, STRSENDERIP, STRIN_INTERFACE, STROUT_INTERFACE, STRBYTES_COL,
    STRCOUNTS, DATEREGDATE
FROM RCA.TB_NOXIOUS_TRAFFIC
WHERE SL.DATEREGDATE = #{dateregdate}::timestamp
    AND SL.STRRESIP = #{strresip}
    AND SL.STRS_IP = #{strsIp}
    AND SL.STRS_PORT = #{strsPort}
    AND SL.STRD_IP = #{strdIp}
    AND SL.STRD_PORT = #{strdPort}

SELECT NREN_NAME, NODE_ID, IF_ID
  FROM RESOURCE.TB_USER_ORGAN
 WHERE NODE_ID = #{nodeId}
   AND IF_ID = #{ifId}
